// ===========================
// UTILITY
// ===========================
function encodePath(p) {
  // Encode each path segment but keep slashes
  return p.split('/').map(seg => encodeURIComponent(seg)).join('/');
}

function capitalize(s) {
  return s.charAt(0).toUpperCase() + s.slice(1).toLowerCase();
}

function titleCase(s) {
  return s.split(/[_ ]+/).map(capitalize).join(' ');
}

// ===========================
// LECCIÓN APRENDIDA — sistema de progreso y navegación
// ===========================
const SECTION_ORDER  = ['resumenes', 'videoclase', 'kahoot', 'simulador', 'anki'];
const SECTION_LABELS = {
  resumenes:  'Resúmenes',
  videoclase: 'Videoclase',
  kahoot:     'Kahoot',
  simulador:  'Simulador',
  anki:       'Anki',
};
const SECTION_POINTS = { resumenes: 10, videoclase: 15, kahoot: 20, simulador: 25, anki: 30 };
const LA_STORAGE_KEY = 'enarmagic_v3';

function _laGetData() {
  try {
    const raw = localStorage.getItem(LA_STORAGE_KEY);
    if (raw) return JSON.parse(raw);
  } catch(e) {}
  return { sectionsComplete: {}, topicsViewed: {}, totalScore: 0, quizScores: [], streakDays: 0, lastVisit: null, scoreLog: [] };
}
function _laSaveData(d) {
  try { localStorage.setItem(LA_STORAGE_KEY, JSON.stringify(d)); } catch(e) {}
}

function isLessonLearned(spId, topicNum, section) {
  const d = _laGetData();
  const key = String(topicNum);
  return !!(d.sectionsComplete[spId] && d.sectionsComplete[spId][key] && d.sectionsComplete[spId][key].includes(section));
}

function markLessonLearned(spId, topicNum, section, btn) {
  const d = _laGetData();
  const key = String(topicNum);
  if (!d.sectionsComplete[spId]) d.sectionsComplete[spId] = {};
  if (!d.sectionsComplete[spId][key]) d.sectionsComplete[spId][key] = [];
  if (!d.sectionsComplete[spId][key].includes(section)) {
    d.sectionsComplete[spId][key].push(section);
    const pts = SECTION_POINTS[section] || 10;
    d.totalScore = (d.totalScore || 0) + pts;
    d.scoreLog = d.scoreLog || [];
    d.scoreLog.push({ date: Date.now(), spId, topicNum, section, pts });
    // Keep topicsViewed in sync (for dashboard compatibility)
    if (!d.topicsViewed[spId]) d.topicsViewed[spId] = [];
    if (!d.topicsViewed[spId].includes(topicNum)) d.topicsViewed[spId].push(topicNum);
    _laSaveData(d);
  }

  // Update button to done state
  if (btn) {
    btn.classList.add('la-btn--done');
    btn.disabled = true;
    const nextIdx = SECTION_ORDER.indexOf(section) + 1;
    const nextSec = SECTION_ORDER[nextIdx];
    btn.innerHTML = nextSec
      ? `<span class="material-symbols-outlined" style="font-size:15px;vertical-align:middle">arrow_forward</span> Ir a ${SECTION_LABELS[nextSec]}`
      : `<span class="material-symbols-outlined" style="font-size:15px;vertical-align:middle">check_circle</span> ¡Tema completo!`;
  }

  // Navigate to next section
  const nextIdx = SECTION_ORDER.indexOf(section) + 1;
  const nextSec = SECTION_ORDER[nextIdx];
  setTimeout(() => {
    if (nextSec) {
      renderSpecialtySection(spId, nextSec);
    } else {
      // All sections done — go to dashboard
      if (typeof window.renderDashboard === 'function') window.renderDashboard();
      showView('dashboard');
    }
  }, 420);
}

function laBtn(spId, topicNum, section) {
  const done = isLessonLearned(spId, topicNum, section);
  const nextIdx = SECTION_ORDER.indexOf(section) + 1;
  const nextSec = SECTION_ORDER[nextIdx];
  const label = done
    ? (nextSec ? `Ir a ${SECTION_LABELS[nextSec]}` : '¡Tema completo!')
    : 'Lección aprendida';
  const icon = done ? (nextSec ? 'arrow_forward' : 'check_circle') : 'school';
  return `<button class="la-btn${done ? ' la-btn--done' : ''}"
    onclick="event.stopPropagation();markLessonLearned('${spId}',${topicNum},'${section}',this)"
    ${done ? 'disabled' : ''}>
    <span class="material-symbols-outlined" style="font-size:15px;vertical-align:middle">${icon}</span>
    ${label}
  </button>`;
}

// Expose score API for future ranking system
window.getUserScore = function() {
  const d = _laGetData();
  return {
    totalScore: d.totalScore || 0,
    sectionsComplete: d.sectionsComplete || {},
    topicsViewed: d.topicsViewed || {},
    scoreLog: d.scoreLog || [],
  };
};

// ===========================
// NAVIGATION
// ===========================
let currentView = 'dashboard';

function showView(viewId) {
  document.querySelectorAll('.view').forEach(v => v.classList.remove('active'));
  // Handle both legacy nav-item and new stitch-nav-item
  document.querySelectorAll('.nav-item, .stitch-nav-item').forEach(n => n.classList.remove('active'));

  const view = document.getElementById('view-' + viewId);
  const nav  = document.getElementById('nav-' + viewId);
  if (view) view.classList.add('active');
  if (nav)  nav.classList.add('active');

  currentView = viewId;

  const titles = {
    dashboard: 'Dashboard',
    cirugia:   'Cirugía',
    pediatria: 'Pediatría',
    gineco:    'Ginecobstetricia',
    medicina:  'Medicina Interna',
    topic:     'Detalle del Tema',
  };
  // Null-guard: topbarTitle may not exist in all HTML layouts
  const _titleEl = document.getElementById('topbarTitle');
  if (_titleEl) _titleEl.textContent = titles[viewId] || viewId;

  if (['cirugia','gineco','medicina','pediatria'].includes(viewId)) {
    renderSpecialtySection(viewId, currentSection[viewId] || 'resumenes');
  }

  // Scroll top — null-guard in case mainContent element id differs
  const _mc = document.getElementById('mainContent');
  if (_mc) _mc.scrollTop = 0;

  // Close sidebar on mobile
  if (window.innerWidth < 768) {
    document.getElementById('sidebar').classList.remove('open');
  }
}


// ===========================
// SECTION TABS
// ===========================
function renderSpecialtySection(spId, section) {
  currentSection[spId] = section;
  
  // Update active tab
  document.querySelectorAll(`[data-sp="${spId}"]`).forEach(tab => {
    tab.classList.toggle('active', tab.dataset.section === section);
  });
  
  const container = document.getElementById(spId + '-content');
  if (!container) return;
  container.innerHTML = '';
  
  const topics = CURRICULUM_DATA[spId] || [];
  
  if (section === 'resumenes') {
    renderResumenes(container, spId, topics);
  } else if (section === 'videoclase') {
    renderVideoclase(container, spId, topics);
  } else if (section === 'kahoot') {
    renderKahoot(container, spId);
  } else if (section === 'simulador') {
    renderSimulador(container, spId);
  } else if (section === 'anki') {
    renderAnki(container, spId);
  } else {
    renderComingSoon(container, SECTION_CONFIG[section]);
  }
}

// ===========================
// HELPER: PREVIEW THUMBNAIL + VIDEO POR ESPECIALIDAD
// Devuelve { thumb, video } para las especialidades con miniaturas propias
// ===========================
function getTopicPreviewPaths(spId, topicNum) {
  if (spId === 'cirugia') {
    const videoFile = CIRUGIA_PREVIEW_VIDEOS[topicNum] || '';
    return {
      thumb: encodePath(`CIRUGIA/Miniaturas cirugia/${topicNum}.jpeg`),
      video: videoFile ? encodePath(`CIRUGIA/Videos cirugia/${videoFile}`) : '',
    };
  }
  if (spId === 'medicina') {
    return {
      thumb: encodePath(`MEDICINA INTERNA/Miniaturas MI/${topicNum}.jpeg`),
      video: encodePath(`MEDICINA INTERNA/Videos MI/${topicNum}.mp4`),
    };
  }
  if (spId === 'pediatria') {
    const videoFile = PEDIATRIA_PREVIEW_VIDEOS[topicNum] || '';
    return {
      thumb: encodePath(`PEDIATRIA/Miniaturas Pedia/${topicNum}.jpeg`),
      video: videoFile ? encodePath(`PEDIATRIA/Videos Pediatria/${videoFile}`) : '',
    };
  }
  if (spId === 'gineco') {
    const videoFile = GINECO_PREVIEW_VIDEOS[topicNum] || '';
    return {
      thumb: encodePath(`GINECOOBSTETRICIA/Miniaturas Gine/${topicNum}.jpeg`),
      video: videoFile ? encodePath(`GINECOOBSTETRICIA/Videos Gine/${videoFile}`) : '',
    };
  }
  return { thumb: '', video: '' };
}

