const SPECIALTIES_WITH_PREVIEW = ['cirugia', 'medicina', 'pediatria', 'gineco'];

// ===========================
// RENDER RESÚMENES
// ===========================
function renderResumenes(container, spId, topics) {
  const cfg = SPECIALTY_CONFIG[spId];
  const topicsWithContent = topics.filter(t =>
    (t.pngs  && t.pngs.length  > 0) ||
    (t.pptxs && t.pptxs.length > 0) ||
    (t.pdfs  && t.pdfs.length  > 0) ||
    (t.csvs  && t.csvs.length  > 0) ||
    (t.mp4s  && t.mp4s.length  > 0)
  );

  if (topicsWithContent.length === 0) {
    container.innerHTML = `<div class="empty-state"><div class="empty-icon">📄</div><p>Resúmenes próximamente disponibles para ${cfg.label}.</p></div>`;
    return;
  }

  container.innerHTML = `<div class="topics-card-grid" id="resumenes-grid-${spId}" data-sp="${spId}"></div>`;
  const grid = container.querySelector('.topics-card-grid');

  const hasPreview = SPECIALTIES_WITH_PREVIEW.includes(spId);

  topicsWithContent.forEach((topic, idx) => {
    const hasPngs  = (topic.pngs  || []).length > 0;
    const hasPptx  = (topic.pptxs || []).length > 0;
    const hasPdfs  = (topic.pdfs  || []).length > 0;
    const hasAny   = hasPptx || hasPdfs || hasPngs;

    const { thumb: pvThumb, video: pvVideo } = hasPreview
      ? getTopicPreviewPaths(spId, topic.num)
      : { thumb: null, video: null };

    const thumbSrc = hasPreview ? pvThumb : (hasPngs ? encodePath(topic.pngs[0]) : null);
    const hasThumb = hasPreview ? true : hasPngs;

    const card = document.createElement('div');
    const _locked = (typeof isTopicAccessible === 'function') && !isTopicAccessible(spId, topic.num);
    card.className = 'topic-card topic-card--clickable' + (_locked ? ' locked' : '');
    card.style.setProperty('--i', idx);
    card.setAttribute('role', 'button');
    card.setAttribute('tabindex', '0');
    card.setAttribute('aria-label', `Abrir contenido: Tema ${topic.num} – ${topic.name}`);

    // Badge pills
    const pptxPill = hasPptx ? `<span class="res-pill res-pill--pptx"><span class="material-symbols-outlined">slideshow</span>PPTX</span>` : '';
    const pdfPill  = hasPdfs ? `<span class="res-pill res-pill--pdf"><span class="material-symbols-outlined">picture_as_pdf</span>PDF</span>` : '';
    const imgPill  = hasPngs && !hasPreview ? `<span class="res-pill res-pill--img"><span class="material-symbols-outlined">photo_library</span>${topic.pngs.length}</span>` : '';

    card.innerHTML = `
      <div class="topic-card-thumb">
        ${hasThumb
          ? `<img class="topic-thumb-img" src="${thumbSrc}" alt="${topic.name}" loading="lazy" onerror="this.style.display='none'" />`
          : `<div class="thumb-placeholder"><span class="material-symbols-outlined">description</span></div>`
        }
        ${hasPreview && pvVideo
          ? `<video class="topic-hover-video" src="${pvVideo}" muted playsinline preload="none" loop></video>`
          : ''
        }
        <!-- Hover overlay: "Ver contenido" -->
        <div class="topic-thumb-open-overlay">
          <span class="material-symbols-outlined topic-thumb-open-icon">open_in_full</span>
          <span class="topic-thumb-open-label">Ver contenido</span>
        </div>
        <div class="topic-card-thumb-overlay"></div>
        <!-- Pill badges bottom-left -->
        <div class="topic-thumb-pills">${pptxPill}${pdfPill}${imgPill}</div>
      </div>
      <div class="topic-card-info">
        <div class="topic-card-num">Tema ${topic.num}</div>
        <div class="topic-card-name">${topic.name}</div>
        ${hasAny
          ? `<div class="topic-card-hub-hint"><span class="material-symbols-outlined" style="font-size:12px">folder_open</span>Toca para ver PDF / PPTX</div>`
          : '<div class="topic-card-hub-hint topic-card-hub-hint--off">Sin contenido disponible</div>'
        }
      </div>
      <div class="topic-card-la">${laBtn(spId, topic.num, 'resumenes')}</div>
      ${_locked ? '<div class="lock-overlay"><span class="material-symbols-outlined">lock</span></div>' : ''}
    `;

    // ── Click entire card → open content hub ──
    if (_locked) {
      card.addEventListener('click', () => {
        if (typeof showUpgradeModal === 'function') showUpgradeModal(spId, topic.num, topic.name);
      });
    } else if (hasAny) {
      card.addEventListener('click', (e) => {
        console.log('[DEBUG] Card click registered!', spId, topic.num);
        // Don't intercept if they clicked the LA button
        if (e.target.closest('.topic-card-la')) return;
        openContentHub(spId, topic.num);
      });
      card.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); openContentHub(spId, topic.num); }
      });
    }

    // Hover video play for specialties with preview
    if (hasPreview && pvVideo) {
      const videoEl = card.querySelector('.topic-hover-video');
      if (videoEl) {
        card.addEventListener('mouseenter', () => videoEl.play().catch(() => {}));
        card.addEventListener('mouseleave', () => { videoEl.pause(); videoEl.currentTime = 0; });
      }
    }

    grid.appendChild(card);
  });
}


