// RENDER VIDEOCLASE
// ===========================
function renderVideoclase(container, spId, topics) {
  const cfg = SPECIALTY_CONFIG[spId];
  const metaTopics = VIDEO_META[spId] || {};
  const topicsWithVideo = Object.values(metaTopics).sort((a,b) => a.num - b.num);

  if (topicsWithVideo.length === 0) {
    container.innerHTML = `<div class="empty-state"><div class="empty-icon">🎬</div><p>Videoclases próximamente para ${cfg.label}.</p></div>`;
    return;
  }

  function fmtDur(sec) {
    if (!sec) return '';
    const m = Math.floor(sec / 60), s = Math.round(sec % 60);
    return `${m}:${String(s).padStart(2,'0')} min`;
  }

  const hasPreview = SPECIALTIES_WITH_PREVIEW.includes(spId);

  container.innerHTML = `
    <div class="vc-topic-list">
      <div class="quiz-list-header">
        <div class="quiz-list-title">Videoclases</div>
        <div class="quiz-list-sub">${topicsWithVideo.length} clases disponibles</div>
      </div>
      <div class="vc-topic-grid" data-sp="${spId}">
        ${topicsWithVideo.map((t, idx) => {
          const hasExpress  = !!t.express;
          const hasComplete = !!t.complete;
          const badge1 = hasExpress  ? `<span class="vc-badge vc-badge--express">⚡ Exprés · ${fmtDur(t.express.duration)}</span>`  : '';
          const badge2 = hasComplete ? `<span class="vc-badge vc-badge--complete">▶ Completa · ${fmtDur(t.complete.duration)}</span>` : '';
          const { thumb: pvThumb, video: pvVideo } = hasPreview ? getTopicPreviewPaths(spId, t.num) : { thumb: '', video: '' };
          const _vcLocked = (typeof isTopicAccessible === 'function') && !isTopicAccessible(spId, t.num);
          return `
          <div class="vc-topic-card${_vcLocked ? ' locked' : ''}" data-sp="${spId}" onclick="${_vcLocked ? `showUpgradeModal('${spId}',${t.num},'${t.name.replace(/'/g,"\\'")}')` : `showVideoTopic('${spId}', ${t.num})`}" style="animation-delay:${idx*0.04}s">
            <div class="vc-card-thumb">
              ${hasPreview && pvThumb ? `<img class="cir-thumb-img" src="${pvThumb}" alt="Tema ${t.num}" loading="lazy" onerror="this.style.display='none'" />` : ''}
              ${hasPreview && pvVideo ? `<video class="topic-hover-video" src="${pvVideo}" muted playsinline preload="none" loop></video>` : ''}
              <div class="vc-card-thumb-bg" style="${hasPreview ? 'background:transparent;' : ''}">
                <span class="material-symbols-outlined" style="${hasPreview ? 'opacity:0;' : ''}">play_circle</span>
              </div>
              <div class="vc-num-badge">Tema ${t.num}</div>
              <div class="vc-play-circle">
                <span class="material-symbols-outlined">play_arrow</span>
              </div>
            </div>
            <div class="vc-card-body">
              <div class="vc-card-name">${t.name}</div>
              <div class="vc-badges">${badge1}${badge2}</div>
              <div class="vc-card-la">${laBtn(spId, t.num, 'videoclase')}</div>
            </div>
            ${_vcLocked ? '<div class="lock-overlay"><span class="material-symbols-outlined">lock</span></div>' : ''}
          </div>`;
        }).join('')}
      </div>
    </div>
  `;

  // Especialidades con preview: hover para reproducir video de animación
  if (hasPreview) {
    container.querySelectorAll('.vc-topic-card').forEach(card => {
      const videoEl = card.querySelector('.topic-hover-video');
      if (!videoEl) return;
      card.addEventListener('mouseenter', () => videoEl.play().catch(() => {}));
      card.addEventListener('mouseleave', () => { videoEl.pause(); videoEl.currentTime = 0; });
    });
  }
}

// ── Active ENARPlayer instances (keyed by panel id) ──────────────────────────
const _enpInstances = {};

function _destroyAllPlayers() {
  for (const key of Object.keys(_enpInstances)) {
    try { _enpInstances[key].destroy(); } catch(e) {}
    delete _enpInstances[key];
  }
}

// Fetch watermark string lazily (email or name from /api/user)
let _enpWatermark = null;
async function _getWatermark() {
  if (_enpWatermark !== null) return _enpWatermark;
  try {
    const r = await fetch('/api/user', { credentials: 'same-origin' });
    if (r.ok) {
      const u = await r.json();
      _enpWatermark = u.email || u.name || '';
    } else { _enpWatermark = ''; }
  } catch(e) { _enpWatermark = ''; }
  return _enpWatermark;
}

// Helper: colour accent per specialty
function _spAccent(spId) {
  const map = {
    cirugia: '#FF4D6D',
    pediatria: '#FFD166',
    gineco: '#FF6FD8',
    medicina: '#06D6A0',
  };
  return map[spId] || '#0EA5E9';
}

function showVideoTopic(spId, topicNum) {
  const container = document.getElementById(spId + '-content');
  if (!container) return;
  const meta = ((VIDEO_META[spId] || {})[String(topicNum)]);
  if (!meta) return;
  const cfg = SPECIALTY_CONFIG[spId];

  function fmtDur(sec) {
    if (!sec) return '';
    const m = Math.floor(sec / 60), s = Math.round(sec % 60);
    return `${m}:${String(s).padStart(2,'0')}`;
  }

  const hasExpress  = !!meta.express;
  const hasComplete = !!meta.complete;
  const hasBoth     = hasExpress && hasComplete;
  const accent      = _spAccent(spId);

  // Build panel placeholder HTML (ENARPlayer will be mounted into .enp-wrap divs)
  const expressPanel = hasExpress ? `
    <div class="vp-panel vp-panel--express">
      <div class="vp-panel-header">
        <span class="vp-panel-icon">⚡</span>
        <div>
          <div class="vp-panel-title">Clase Exprés</div>
          <div class="vp-panel-sub">Versión resumida · ${fmtDur(meta.express.duration)} min</div>
        </div>
      </div>
      <div class="enp-wrap" id="enp-express-${spId}-${topicNum}"></div>
    </div>` : '';

  const completePanel = hasComplete ? `
    <div class="vp-panel vp-panel--complete">
      <div class="vp-panel-header">
        <span class="vp-panel-icon">📹</span>
        <div>
          <div class="vp-panel-title">Clase Completa</div>
          <div class="vp-panel-sub">Versión extendida · ${fmtDur(meta.complete.duration)} min</div>
        </div>
      </div>
      <div class="enp-wrap" id="enp-complete-${spId}-${topicNum}"></div>
    </div>` : '';

  // Destroy any existing players before re-rendering
  _destroyAllPlayers();

  container.innerHTML = `
    <div class="video-player-view">
      <div class="vp-header">
        <button class="qs-back" onclick="_destroyAllPlayers(); renderSpecialtySection('${spId}','videoclase')">
          ← Todas las clases
        </button>
        <div class="vp-title">
          <span class="vp-num">Tema ${meta.num} · ${cfg.label}</span>
          <span class="vp-name">${meta.name}</span>
        </div>
      </div>
      <div class="vp-panels ${hasBoth ? 'vp-panels--two' : 'vp-panels--one'}">
        ${expressPanel}
        ${completePanel}
      </div>
      <div class="vp-la-row">${laBtn(spId, meta.num, 'videoclase')}</div>
    </div>
  `;

  // Mount players immediately with direct URL (protected by session auth),
  // then asynchronously upgrade to signed-token URL for extra security.
  _mountPlayers(spId, topicNum, meta, accent);
}

function _mountPlayers(spId, topicNum, meta, accent) {
  const hasExpress  = !!meta.express;
  const hasComplete = !!meta.complete;

  // Helper: encode path for direct use as URL
  function directUrl(rawPath) {
    return rawPath.split('/').map(seg => encodeURIComponent(seg)).join('/');
  }

  // Mount express player immediately
  if (hasExpress) {
    const el = document.getElementById(`enp-express-${spId}-${topicNum}`);
    if (el) {
      const key = `express-${spId}-${topicNum}`;
      const url = directUrl(meta.express.path);
      _enpInstances[key] = new ENARPlayer(el, url, {
        accent, watermark: _enpWatermark || '', title: meta.name, label: 'Exprés'
      });
    }
  }

  // Mount complete player immediately
  if (hasComplete) {
    const el = document.getElementById(`enp-complete-${spId}-${topicNum}`);
    if (el) {
      const key = `complete-${spId}-${topicNum}`;
      const url = directUrl(meta.complete.path);
      _enpInstances[key] = new ENARPlayer(el, url, {
        accent, watermark: _enpWatermark || '', title: meta.name, label: 'Completa'
      });
    }
  }

  // Asynchronously upgrade to signed token URLs + set watermark
  _upgradeToSecureUrls(spId, topicNum, meta, accent);
}

async function _upgradeToSecureUrls(spId, topicNum, meta, accent) {
  try {
    const wm = await _getWatermark();
    const hasExpress  = !!meta.express;
    const hasComplete = !!meta.complete;

    if (hasExpress) {
      const key = `express-${spId}-${topicNum}`;
      const inst = _enpInstances[key];
      if (inst && !inst._destroyed) {
        const secUrl = await getSecureVideoUrl(meta.express.path);
        // Only switch if URL actually improved (token-based)
        if (secUrl.startsWith('/api/video-stream')) {
          const pos = inst.video.currentTime;
          inst.setSrc(secUrl);
          inst.video.currentTime = pos;
        }
        if (wm) inst.watermark.textContent = wm;
      }
    }
    if (hasComplete) {
      const key = `complete-${spId}-${topicNum}`;
      const inst = _enpInstances[key];
      if (inst && !inst._destroyed) {
        const secUrl = await getSecureVideoUrl(meta.complete.path);
        if (secUrl.startsWith('/api/video-stream')) {
          const pos = inst.video.currentTime;
          inst.setSrc(secUrl);
          inst.video.currentTime = pos;
        }
        if (wm) inst.watermark.textContent = wm;
      }
    }
  } catch(e) {
    // Non-fatal: players already work with direct URLs
  }
}

function toggleVideo(header) {
  const body = header.nextElementSibling;
  const icon = header.querySelector('.video-toggle-icon');
  const isOpen = body.style.display !== 'none';
  body.style.display = isOpen ? 'none' : 'block';
  icon.textContent = isOpen ? '▶' : '▼';
  if (!isOpen) {
    const video = body.querySelector('video');
    if (video) video.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  }
}

function switchVideo(btn, src) {
  const body = btn.closest('.video-body');
  body.querySelectorAll('.video-tab').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  const video = body.querySelector('video source');
  const videoEl = body.querySelector('video');
  video.src = src;
  videoEl.load();
}

