function openContentHub(spId, topicNum) {
  console.log('[DEBUG] openContentHub called:', spId, typeof topicNum, topicNum);
  const topics = (CURRICULUM_DATA[spId] || []);
  const topic  = topics.find(t => String(t.num) === String(topicNum));
  if (!topic) {
    console.error('[DEBUG] -> Topic NOT FOUND! Topics available:', topics.map(t=>t.num));
    return;
  }

  console.log('[DEBUG] Topic found:', topic.name);
  _hubCurrentTopic = topic;
  _hubCurrentSpId  = spId;

  const hasPptx = topic.pptxs && topic.pptxs.length > 0;
  const hasPdfs = topic.pdfs  && topic.pdfs.length  > 0;
  console.log('[DEBUG] hasPptx:', hasPptx, 'hasPdfs:', hasPdfs);


  // Always show the 2-button picker — never skip it
  const overlay = document.getElementById('contentHubOverlay');
  document.getElementById('hubTopicNum').textContent  = ('TEMA ' + topic.num).toUpperCase();
  document.getElementById('hubTopicName').textContent = topic.name.toUpperCase();

  const grid = document.getElementById('contentHubGrid');
  grid.innerHTML = '';
  grid.style.gridTemplateColumns = 'repeat(2, 1fr)';
  grid.style.gap = '16px';
  grid.style.maxWidth = '480px';
  grid.style.margin = '0 auto';

  // Helper: build a button using DOM (avoids JSON/quote conflicts in innerHTML)
  function makeHubBtn(type, files, iconName, label, badgeText, badgeClass, btnClass) {
    const btn = document.createElement('button');
    btn.className = 'hub-big-btn ' + btnClass;
    btn.innerHTML =
      '<span class="material-symbols-outlined hub-big-icon">' + iconName + '</span>' +
      '<span class="hub-big-label">' + label + '</span>' +
      '<span class="hub-big-badge ' + (badgeClass||'') + '">' + badgeText + '</span>';
    btn.addEventListener('click', function() {
      openFileViewer(type, encodePath(files[0]), files);
    });
    return btn;
  }

  function makeHubDisabled(iconName, label) {
    const div = document.createElement('div');
    div.className = 'hub-big-btn hub-big-disabled';
    div.innerHTML =
      '<span class="material-symbols-outlined hub-big-icon">' + iconName + '</span>' +
      '<span class="hub-big-label">' + label + '</span>' +
      '<span class="hub-big-badge hub-big-badge-off">Pronto</span>';
    return div;
  }

  // --- PPTX card ---
  const pptxDiv = document.createElement('div');
  pptxDiv.appendChild(
    hasPptx
      ? makeHubBtn('pptx', topic.pptxs, 'slideshow', 'Presentación', 'PPTX', '', 'hub-big-pptx')
      : makeHubDisabled('slideshow', 'Presentación')
  );
  grid.appendChild(pptxDiv);

  // --- PDF card ---
  const pdfDiv = document.createElement('div');
  pdfDiv.appendChild(
    hasPdfs
      ? makeHubBtn('pdf', topic.pdfs, 'picture_as_pdf', 'Resumen PDF', 'PDF', 'hub-pdf-badge', 'hub-big-pdf')
      : makeHubDisabled('picture_as_pdf', 'Resumen PDF')
  );
  console.log('[DEBUG] Appending children to grid');
  grid.appendChild(pdfDiv);

  console.log('[DEBUG] Opening overlay');
  overlay.classList.add('open');
  console.log('[DEBUG] Overlay classList:', overlay.className);
}

function closeContentHub() {
  const ov = document.getElementById('contentHubOverlay');
  if (ov) ov.classList.remove('open');
}

// Wire content hub close
(function wireHub() {
  function init() {
    const hubOverlay = document.getElementById('contentHubOverlay');
    if (!hubOverlay) { setTimeout(init, 100); return; }
    hubOverlay.addEventListener('click', e => { if (e.target === hubOverlay) closeContentHub(); });
    document.getElementById('contentHubClose').addEventListener('click', closeContentHub);
    document.addEventListener('keydown', e => {
      if (e.key === 'Escape') { closeContentHub(); closeFileViewer(); }
    });
    // Wire file viewer buttons
    document.getElementById('fileViewerClose').addEventListener('click', closeFileViewer);
    document.getElementById('fileViewerBack').addEventListener('click', () => {
      closeFileViewer();
      if (_hubCurrentTopic) openContentHub(_hubCurrentSpId, _hubCurrentTopic.num);
    });
    document.getElementById('pptxPrev').addEventListener('click', () => navigatePptx(-1));
    document.getElementById('pptxNext').addEventListener('click', () => navigatePptx(1));

    // Helper: toggle fullscreen and update all fullscreen button icons
    function _toggleFullscreen() {
      const stage = document.getElementById('fileViewerOverlay');
      if (!document.fullscreenElement) {
        (stage.requestFullscreen || stage.webkitRequestFullscreen || stage.mozRequestFullScreen || stage.msRequestFullscreen || (() => {})).call(stage);
      } else {
        (document.exitFullscreen || document.webkitExitFullscreen || document.mozCancelFullScreen || document.msExitFullscreen || (() => {})).call(document);
      }
    }
    // Update icon when fullscreen state changes
    document.addEventListener('fullscreenchange', () => {
      const isFs = !!document.fullscreenElement;
      ['pptxFullscreen','pdfFullscreen'].forEach(id => {
        const btn = document.getElementById(id);
        if (btn) btn.querySelector('.material-symbols-outlined').textContent = isFs ? 'fullscreen_exit' : 'fullscreen';
      });
      // Re-fit slide after entering/exiting fullscreen
      setTimeout(_fitPptxSlide, 120);
    });

    document.getElementById('pptxFullscreen').addEventListener('click', _toggleFullscreen);
    document.getElementById('pdfPrev').addEventListener('click', () => navigatePdf(-1));
    document.getElementById('pdfNext').addEventListener('click', () => navigatePdf(1));
    document.getElementById('pdfFullscreen').addEventListener('click', _toggleFullscreen);
    document.getElementById('imgPrev').addEventListener('click', () => navigateImg(-1));
    document.getElementById('imgNext').addEventListener('click', () => navigateImg(1));

    // Keyboard navigation within the file viewer
    document.addEventListener('keydown', e => {
      const viewerOpen = document.getElementById('fileViewerOverlay').classList.contains('open');
      if (!viewerOpen) return;
      const type = _viewerState.type;
      if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
        e.preventDefault();
        if (type === 'pptx') navigatePptx(1);
        else if (type === 'pdf')  navigatePdf(1);
        else if (type === 'img')  navigateImg(1);
      } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
        e.preventDefault();
        if (type === 'pptx') navigatePptx(-1);
        else if (type === 'pdf')  navigatePdf(-1);
        else if (type === 'img')  navigateImg(-1);
      } else if (e.key === 'f' || e.key === 'F') {
        _toggleFullscreen();
      }
    });
  }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else init();
})();

// ===========================
// FILE VIEWER (PPTX / DOCX / PDF / IMG)
// ===========================

let _viewerState = { type:null, files:[], currentFileIdx:0, images:[], currentImg:0 };

function openFileViewer(type, primaryPath, allPaths) {
  closeContentHub();
  const overlay = document.getElementById('fileViewerOverlay');

  _viewerState.type = type;
  _viewerState.files = allPaths || [primaryPath];
  _viewerState.currentFileIdx = 0;

  const dlBtn = document.getElementById('fileViewerDownload');
  dlBtn.href = primaryPath;
  dlBtn.download = decodeURIComponent(primaryPath.split('/').pop());

  ['pptxViewer','pdfViewer','docxViewer','ankiViewer','imgViewer'].forEach(id => {
    document.getElementById(id).style.display = 'none';
  });

  const typeIcon = document.getElementById('fileViewerTypeIcon');
  const fileNameEl = document.getElementById('fileViewerFileName');

  if (type === 'pptx') {
    typeIcon.textContent = 'slideshow'; typeIcon.style.color = '#FF6FD8';
    fileNameEl.textContent = decodeURIComponent(primaryPath.split('/').pop()).replace(/_/g,' ').replace(/\.pptx$/i,'');
    document.getElementById('pptxViewer').style.display = 'flex';
    loadPptxViewer(allPaths);
  } else if (type === 'pdf') {
    typeIcon.textContent = 'picture_as_pdf'; typeIcon.style.color = '#FF4D6D';
    fileNameEl.textContent = decodeURIComponent(primaryPath.split('/').pop()).replace(/_/g,' ').replace(/\.pdf$/i,'');
    document.getElementById('pdfViewer').style.display = 'flex';
    loadPdfViewer(primaryPath);
  } else if (type === 'docx') {
    typeIcon.textContent = 'description'; typeIcon.style.color = '#00E5FF';
    fileNameEl.textContent = decodeURIComponent(primaryPath.split('/').pop()).replace(/_/g,' ').replace(/\.docx$/i,'');
    document.getElementById('docxViewer').style.display = 'flex';
    loadDocxViewer(primaryPath);
  } else if (type === 'anki') {
    typeIcon.textContent = 'style'; typeIcon.style.color = '#818CF8';
    fileNameEl.textContent = 'Flashcards Anki';
    // Download button: only show if we have a real file path
    dlBtn.href = primaryPath;
    dlBtn.download = decodeURIComponent(primaryPath.split('/').pop());
    document.getElementById('ankiViewer').style.display = 'flex';
    loadAnkiViewer(primaryPath);
  } else if (type === 'img') {
    typeIcon.textContent = 'photo_library'; typeIcon.style.color = '#FFD166';
    fileNameEl.textContent = 'Galería de imágenes';
    document.getElementById('imgViewer').style.display = 'flex';
    loadImgViewer(allPaths);
  }

  overlay.classList.add('open');
}

function closeFileViewer() {
  const ov = document.getElementById('fileViewerOverlay');
  if (ov) ov.classList.remove('open');
  // Reset PDF state
  _pdfState.pdf = null; _pdfState.pageNum = 1; _pdfState.pageCount = 0;
  const wrap = document.getElementById('pdfCanvasWrap');
  if (wrap) wrap.innerHTML = '';
  const pdfLoading = document.getElementById('pdfLoading');
  if (pdfLoading) pdfLoading.style.display = 'none';
  const pdfControls = document.getElementById('pdfControls');
  if (pdfControls) pdfControls.style.display = 'none';
}

// ===========================
// PDF.js VIEWER
