const _pdfState = { pdf: null, pageNum: 1, pageCount: 0, rendering: false };

async function loadPdfViewer(path) {
  const wrap     = document.getElementById('pdfCanvasWrap');
  const loading  = document.getElementById('pdfLoading');
  const controls = document.getElementById('pdfControls');

  wrap.innerHTML = '';
  loading.style.display    = 'flex';
  controls.style.display   = 'none';
  _pdfState.rendering = false;
  _pdfState.pdf = null;

  try {
    if (typeof pdfjsLib === 'undefined') throw new Error('PDF.js not loaded');
    pdfjsLib.GlobalWorkerOptions.workerSrc =
      'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

    const loadTask = pdfjsLib.getDocument(path);
    const pdf = await loadTask.promise;
    _pdfState.pdf        = pdf;
    _pdfState.pageNum    = 1;
    _pdfState.pageCount  = pdf.numPages;

    loading.style.display  = 'none';
    controls.style.display = 'flex';
    document.getElementById('pdfPrev').disabled = true;
    document.getElementById('pdfNext').disabled = pdf.numPages <= 1;
    await _renderPdfPage(1);
  } catch(e) {
    const fname = decodeURIComponent(path.split('/').pop());
    loading.innerHTML = `
      <div style="text-align:center;padding:40px;">
        <span class="material-symbols-outlined" style="font-size:48px;color:#FF4D6D;opacity:0.7">picture_as_pdf</span>
        <p style="color:#94A3B8;margin:16px 0 24px;font-size:14px;">
          No se pudo cargar el PDF en el visor.<br>Puedes descargarlo directamente.
        </p>
        <a href="${path}" download="${fname}"
           style="display:inline-flex;align-items:center;gap:8px;
                  background:rgba(255,77,109,0.12);border:1px solid rgba(255,77,109,0.4);
                  border-radius:10px;padding:12px 24px;color:#FF4D6D;font-weight:600;
                  font-size:14px;text-decoration:none;">
          <span class="material-symbols-outlined">download</span> Descargar PDF
        </a>
      </div>`;
  }
}

async function _renderPdfPage(pageNum) {
  if (!_pdfState.pdf || _pdfState.rendering) return;
  _pdfState.rendering = true;
  const wrap = document.getElementById('pdfCanvasWrap');
  try {
    const page        = await _pdfState.pdf.getPage(pageNum);
    const nativeVp    = page.getViewport({ scale: 1 });
    const dpr         = window.devicePixelRatio || 1;

    // Fit the page within the available container, respecting both width AND height.
    const padH = 32, padW = 32;
    const availW = Math.max((wrap.clientWidth  || 800) - padW, 200);
    const availH = Math.max((wrap.clientHeight || 600) - padH, 200);
    const scaleByW = availW / nativeVp.width;
    const scaleByH = availH / nativeVp.height;
    // Use whichever scale would cause overflow first, capped at 2× for sharpness
    const cssScale = Math.min(scaleByW, scaleByH, 2.0);

    const viewport = page.getViewport({ scale: cssScale * dpr });

    const canvas   = document.createElement('canvas');
    canvas.width   = viewport.width;
    canvas.height  = viewport.height;
    // Display at CSS size (sharp on HiDPI)
    canvas.style.width  = Math.round(viewport.width  / dpr) + 'px';
    canvas.style.height = Math.round(viewport.height / dpr) + 'px';

    wrap.innerHTML = '';
    wrap.appendChild(canvas);

    await page.render({ canvasContext: canvas.getContext('2d'), viewport }).promise;

    _pdfState.pageNum   = pageNum;
    _pdfState.rendering = false;

    document.getElementById('pdfCounter').textContent = `${pageNum} / ${_pdfState.pageCount}`;
    document.getElementById('pdfPrev').disabled = pageNum <= 1;
    document.getElementById('pdfNext').disabled = pageNum >= _pdfState.pageCount;
  } catch(e) {
    _pdfState.rendering = false;
  }
}

function navigatePdf(dir) {
  const next = _pdfState.pageNum + dir;
  if (next >= 1 && next <= _pdfState.pageCount && !_pdfState.rendering)
    _renderPdfPage(next);
}

// ===========================
// PPTX Viewer (JSZip-based)
// ===========================
let _pptxSlides  = [];
let _pptxCurrent = 0;

// Strip XML namespace prefixes correctly so DOMParser querySelector works
function _stripNs(xml) {
  let s = xml;
  // Remove namespace declarations first
  s = s.replace(/\s+xmlns(?::[a-zA-Z0-9_]+)?="[^"]*"/g, '');
  // IMPORTANT: rename r:id → rid  and r:embed → rembed BEFORE generic stripping
  // to avoid collision with the regular id= attribute on the same element
  s = s.replace(/\br:id\s*=/g,    'rid=');
  s = s.replace(/\br:embed\s*=/g, 'rembed=');
  // Remove namespace prefixes from ELEMENT names: <p:sp → <sp, </a:txBody → </txBody
  // Single regex, correct replacement using $1 (slash) + $2 (local name)
  s = s.replace(/<(\/?)[a-zA-Z][a-zA-Z0-9_]*:([a-zA-Z][a-zA-Z0-9_]*)/g, '<$1$2');
  // Remove remaining namespace prefixes from other ATTRIBUTE names
  s = s.replace(/\b[a-zA-Z][a-zA-Z0-9_]*:([a-zA-Z][a-zA-Z0-9_]*)\s*=/g, '$1=');
  return s;
}

async function loadPptxViewer(pptxPaths) {
  const slidesWrap = document.getElementById('pptxSlidesWrap');
  const loading    = document.getElementById('pptxLoading');
  const controls   = document.getElementById('pptxControls');
  const selector   = document.getElementById('pptxSelector');

  loading.style.display    = 'flex';
  slidesWrap.style.display = 'none';
  controls.style.display   = 'none';
  selector.style.display   = 'none';
  slidesWrap.innerHTML     = '';
  _pptxSlides  = [];
  _pptxCurrent = 0;

  if (pptxPaths && pptxPaths.length > 1) {
    selector.style.display = 'flex';
    selector.innerHTML = pptxPaths.map((p, i) => {
      const name = decodeURIComponent(p.split('/').pop()).replace(/_/g,' ').replace(/\.pptx$/i,'');
      return `<button class="pptx-sel-btn${i===0?' active':''}" onclick="switchPptxFile(${i})" title="${name}">${name}</button>`;
    }).join('');
  }

  await _loadPptxFile(encodePath(pptxPaths[0]), loading, slidesWrap, controls);
}

async function switchPptxFile(idx) {
  _viewerState.currentFileIdx = idx;
  document.querySelectorAll('.pptx-sel-btn').forEach((b,i) => b.classList.toggle('active', i===idx));
  const loading    = document.getElementById('pptxLoading');
  const slidesWrap = document.getElementById('pptxSlidesWrap');
  const controls   = document.getElementById('pptxControls');
  loading.style.display    = 'flex';
  slidesWrap.style.display = 'none';
  controls.style.display   = 'none';
  slidesWrap.innerHTML     = '';
  _pptxSlides = []; _pptxCurrent = 0;
  await _loadPptxFile(encodePath(_viewerState.files[idx]), loading, slidesWrap, controls);
}

async function _loadPptxFile(path, loading, slidesWrap, controls) {
  try {
    if (typeof JSZip === 'undefined') throw new Error('JSZip not loaded');

    const resp = await fetch(path);
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    const buf  = await resp.arrayBuffer();
    const zip  = await JSZip.loadAsync(buf);

    const parser = new DOMParser();

    // ---- 1. Get ordered slide file paths from presentation rels ----
    const presRelRaw = await zip.file('ppt/_rels/presentation.xml.rels').async('text');
    const presRelXml = _stripNs(presRelRaw);
    const relDoc     = parser.parseFromString(presRelXml, 'text/xml');
    const relMap     = {};
    relDoc.querySelectorAll('Relationship').forEach(r => {
      relMap[r.getAttribute('Id')] = r.getAttribute('Target');
    });

    // ---- 2. Get slide order and dimensions from presentation.xml ----
    const presRaw = await zip.file('ppt/presentation.xml').async('text');
    const presXml = _stripNs(presRaw);
    const presDoc = parser.parseFromString(presXml, 'text/xml');

    // Read actual slide dimensions (EMU units) — critical for correct layout
    let slideW = 9144000, slideH = 5143500;  // default 10"×5.625" (16:9)
    const sldSzEl = presDoc.querySelector('sldSz');
    if (sldSzEl) {
      const cx = parseInt(sldSzEl.getAttribute('cx') || 0);
      const cy = parseInt(sldSzEl.getAttribute('cy') || 0);
      if (cx > 0 && cy > 0) { slideW = cx; slideH = cy; }
    }

    let slidePaths = [];
    // After stripNs: <sldId id="256" rid="rId2"/> — use rid attr
    presDoc.querySelectorAll('sldIdLst sldId').forEach(el => {
      const rid    = el.getAttribute('rid');
      const target = relMap[rid];
      if (target) slidePaths.push('ppt/' + target.replace(/^\.\.\//, ''));
    });

    // Fallback: enumerate slides from ZIP directly sorted by number
    if (slidePaths.length === 0) {
      const found = [];
      zip.forEach((p) => { if (/^ppt\/slides\/slide\d+\.xml$/.test(p)) found.push(p); });
      found.sort((a,b) => {
        return parseInt(a.match(/(\d+)\.xml$/)[1]) - parseInt(b.match(/(\d+)\.xml$/)[1]);
      });
      slidePaths = found;
    }
    if (slidePaths.length === 0) throw new Error('No slides found');

    // ---- 3. Extract media as Blob URLs (keyed by filename) ----
    const mediaMap = {};
    const mimeOf   = { png:'image/png', jpg:'image/jpeg', jpeg:'image/jpeg',
                       gif:'image/gif', svg:'image/svg+xml', bmp:'image/bmp',
                       wmf:'image/x-wmf', emf:'image/x-emf' };
    const mediaTasks = [];
    zip.forEach((relPath, file) => {
      if (!relPath.startsWith('ppt/media/')) return;
      const fname = relPath.split('/').pop();
      const ext   = fname.split('.').pop().toLowerCase();
      const mime  = mimeOf[ext] || 'application/octet-stream';
      mediaTasks.push(
        file.async('arraybuffer').then(ab => {
          mediaMap[fname] = URL.createObjectURL(new Blob([ab], { type: mime }));
        })
      );
    });
    await Promise.all(mediaTasks);

    // ---- 4. Render each slide ----
    _pptxSlides = [];
    for (const slidePath of slidePaths) {
      const sf = zip.file(slidePath);
      if (!sf) continue;

      // Resolve slide's own rels (for image r:embed lookups)
      const slideRelPath = slidePath.replace(/\/([^/]+)$/, '/_rels/$1.rels');
      const slideRelMap  = {};
      const srf = zip.file(slideRelPath);
      if (srf) {
        const srXml = _stripNs(await srf.async('text'));
        const srDoc = parser.parseFromString(srXml, 'text/xml');
        srDoc.querySelectorAll('Relationship').forEach(r => {
          const tgt  = r.getAttribute('Target') || '';
          const fname = tgt.split('/').pop();
          // key by rid (from r:id after stripNs) AND by Id
          slideRelMap[r.getAttribute('Id')]  = fname;
          slideRelMap[r.getAttribute('rid')] = fname;
        });
      }

      const raw  = await sf.async('text');
      const xml  = _stripNs(raw);
      const html = _buildSlideHtml(xml, slideRelMap, mediaMap, slideW, slideH);
      _pptxSlides.push(html);
    }

    if (_pptxSlides.length === 0) throw new Error('No slides built');

    loading.style.display    = 'none';
    slidesWrap.style.display = 'flex';
    controls.style.display   = 'flex';
    _showPptxSlide(0);
    _attachPptxResizeObserver();

  } catch(err) {
    console.error('PPTX viewer error:', err);
    _renderPptxFallback(path, loading, slidesWrap);
  }
}

// Standard PPTX slide dimensions in EMUs
const _SLIDE_W = 9144000;
const _SLIDE_H = 5143500;

function _pctOf(val, total) { return (parseInt(val) / total * 100).toFixed(2); }

function _buildSlideHtml(slideXml, slideRelMap, mediaMap, slideW, slideH) {
  slideW = slideW || 9144000;
  slideH = slideH || 5143500;
  // Pre-rename PPTX short elements that conflict with HTML parsing
  // After _stripNs: <p>=paragraph, <r>=run, <t>=text — HTML mangles <p> especially
  let xml = slideXml;
  xml = xml.replace(/<(\/?)(p)(\s|\/|>)/g, '<$1pp$3');
  xml = xml.replace(/<(\/?)(r)(\s|\/|>)/g, '<$1rr$3');
  xml = xml.replace(/<(\/?)(t)(\s|\/|>)/g, '<$1tt$3');

  // Use lenient HTML parsing (innerHTML) instead of DOMParser xml mode
  // HTML mode is much more resilient to PPTX's often-complex XML
  const tempDiv = document.createElement('div');
  tempDiv.innerHTML = xml;
  // HTML parser lowercases all tag names: sp→sp, txbody→txbody, sppr→sppr, etc.

  // Background colour — look for srgbclr inside bg element
  let bgColor = '#1a1f2e';
  const bgEl = tempDiv.querySelector('bg');
  if (bgEl) {
    const bgs = bgEl.querySelector('srgbclr');
    if (bgs) { const v = bgs.getAttribute('val'); if (v) bgColor = '#' + v; }
  }

  const items = [];

  // ---- Image shapes: pic > blipfill > blip[rembed] ----
  tempDiv.querySelectorAll('pic').forEach(pic => {
    const blip = pic.querySelector('blip');
    if (!blip) return;
    const rid  = blip.getAttribute('rembed') || blip.getAttribute('embed') || blip.getAttribute('r:embed');
    if (!rid) return;
    const fname = slideRelMap[rid];
    const burl  = fname ? mediaMap[fname] : null;
    if (!burl) return;

    const off = pic.querySelector('off');
    const ext = pic.querySelector('ext');
    if (!off || !ext) return;

    const l = _pctOf(off.getAttribute('x') || 0, slideW);
    const t = _pctOf(off.getAttribute('y') || 0, slideH);
    const w = _pctOf(ext.getAttribute('cx') || 0, slideW);
    const h = _pctOf(ext.getAttribute('cy') || 0, slideH);
    items.push(`<img src="${burl}" style="position:absolute;left:${l}%;top:${t}%;width:${w}%;height:${h}%;object-fit:contain;object-position:center;" />`);
  });

  // ---- Text shapes: sp > txbody > pp > rr > tt ----
  tempDiv.querySelectorAll('sp').forEach(sp => {
    const txBody = sp.querySelector('txbody');
    if (!txBody) return;

    const off = sp.querySelector('off');
    const ext = sp.querySelector('ext');
    const l = off ? _pctOf(off.getAttribute('x') || 0, slideW) : '0';
    const t = off ? _pctOf(off.getAttribute('y') || 0, slideH) : '0';
    const w = ext ? _pctOf(ext.getAttribute('cx') || slideW, slideW) : '100';
    const h = ext ? _pctOf(ext.getAttribute('cy') || slideH/8, slideH) : '12.5';

    const paraHtmls = [];
    txBody.querySelectorAll('pp').forEach(para => {
      const pPr  = para.querySelector('ppr');
      const algn = pPr ? (pPr.getAttribute('algn') || 'l') : 'l';
      const align = algn === 'ctr' ? 'center' : algn === 'r' ? 'right' : 'left';
      const spc  = pPr ? parseInt(pPr.getAttribute('spcbef') || pPr.getAttribute('spcBef') || 0) : 0;

      let paraText = '';
      para.querySelectorAll('rr').forEach(run => {
        const tEl = run.querySelector('tt');
        if (!tEl || !tEl.textContent.trim()) return;
        const rPr = run.querySelector('rpr');
        let sz = 13, clr = '#ffffff', bld = false, ital = false;
        if (rPr) {
          const szA = parseInt(rPr.getAttribute('sz') || 0);
          if (szA > 0) sz = Math.min(56, Math.max(7, Math.round(szA / 100)));
          const sc = rPr.querySelector('srgbclr');
          if (sc) { const v = sc.getAttribute('val'); if (v) clr = '#' + v; }
          bld  = rPr.getAttribute('b') === '1';
          ital = rPr.getAttribute('i') === '1';
        }
        const txt = tEl.textContent.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        paraText += `<span style="font-size:${sz}px;color:${clr};font-weight:${bld?700:400};font-style:${ital?'italic':'normal'};">${txt}</span>`;
      });

      if (paraText) {
        const mt = spc > 0 ? Math.round(spc / 12700) : 0;
        paraHtmls.push(`<div style="text-align:${align};margin-top:${mt}px;line-height:1.3;">${paraText}</div>`);
      }
    });

    if (paraHtmls.length === 0) return;
    items.push(`<div style="position:absolute;left:${l}%;top:${t}%;width:${w}%;min-height:${h}%;overflow:hidden;padding:2px 5px;word-break:break-word;">${paraHtmls.join('')}</div>`);
  });

  // Fallback: if no items found, extract all text nodes from renamed <tt> elements
  if (items.length === 0) {
    const texts = [];
    tempDiv.querySelectorAll('tt').forEach(el => {
      const txt = el.textContent.trim();
      if (txt) texts.push(txt);
    });
    if (texts.length > 0) {
      const escTexts = texts.map(t => t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'));
      items.push(`<div style="position:absolute;inset:8%;display:flex;flex-direction:column;justify-content:center;gap:4px;">${
        escTexts.map(t => `<div style="color:#fff;font-size:14px;line-height:1.4;">${t}</div>`).join('')
      }</div>`);
    }
  }

  return `<div class="pptx-rendered-slide" style="position:relative;width:100%;padding-top:${(slideH/slideW*100).toFixed(3)}%;background:${bgColor};border-radius:10px;overflow:hidden;box-shadow:0 16px 64px rgba(0,0,0,0.75);">
    <div style="position:absolute;inset:0;">${items.join('')}</div>
  </div>`;
}

function _renderPptxFallback(path, loading, slidesWrap) {
  const fname = decodeURIComponent(path.split('/').pop()).replace(/_/g,' ').replace(/\.pptx$/i,'');
  loading.style.display    = 'none';
  slidesWrap.style.display = 'flex';
  slidesWrap.innerHTML = `
    <div class="pptx-slide-placeholder">
      <span class="material-symbols-outlined">slideshow</span>
      <h3>${fname}</h3>
      <p>Descarga la presentación para verla con todas las animaciones y transiciones.</p>
      <a class="pptx-open-btn" href="${path}" download>
        <span class="material-symbols-outlined">download</span>Descargar PPTX
      </a>
    </div>`;
}

function _showPptxSlide(idx) {
  const slidesWrap = document.getElementById('pptxSlidesWrap');
  if (!_pptxSlides[idx]) return;
  slidesWrap.innerHTML = _pptxSlides[idx];
  _pptxCurrent = idx;
  const total = _pptxSlides.length;
  document.getElementById('pptxCounter').textContent = `${idx + 1} / ${total}`;
  document.getElementById('pptxPrev').disabled = idx <= 0;
  document.getElementById('pptxNext').disabled = idx >= total - 1;
  // Fit slide to available space without stretching
  _fitPptxSlide();
}

// Constrain the PPTX slide so it never overflows the stage,
// while preserving the correct aspect ratio.
let _pptxResizeObs = null;
function _fitPptxSlide() {
  const stage = document.getElementById('pptxStage');
  const wrap  = document.getElementById('pptxSlidesWrap');
  const slide = wrap && wrap.querySelector('.pptx-rendered-slide');
  if (!stage || !slide) return;

  // Read H/W ratio encoded in the padding-top (e.g. "56.250%")
  const ptStr = slide.style.paddingTop || '';
  const hwRatio = ptStr.includes('%') ? (parseFloat(ptStr) / 100) : (9 / 16);

  // Available viewport (subtract 2×20px padding from both axes)
  const availW = Math.max(stage.clientWidth  - 40, 100);
  const availH = Math.max(stage.clientHeight - 56, 100); // extra for controls

  // Width such that height (= width × hwRatio) ≤ availH
  const maxW = Math.min(availW, Math.floor(availH / hwRatio));
  slide.style.width = maxW + 'px';
}

// Auto-refit on stage resize (handles window resize & fullscreen toggle)
function _attachPptxResizeObserver() {
  const stage = document.getElementById('pptxStage');
  if (!stage || !window.ResizeObserver) return;
  if (_pptxResizeObs) _pptxResizeObs.disconnect();
  _pptxResizeObs = new ResizeObserver(() => _fitPptxSlide());
  _pptxResizeObs.observe(stage);
}

function navigatePptx(dir) {
  const next = _pptxCurrent + dir;
  if (next >= 0 && next < _pptxSlides.length) _showPptxSlide(next);
}

// ===========================
// DOCX Viewer (mammoth.js)
function loadDocxViewer(path) {
  const content = document.getElementById('docxContent');
  content.innerHTML = '<div class="docx-loading-msg">⏳ Cargando documento Word…</div>';

  fetch(path)
    .then(r => { if (!r.ok) throw new Error('fetch failed'); return r.arrayBuffer(); })
    .then(buf => {
      if (typeof mammoth !== 'undefined') {
        return mammoth.convertToHtml({ arrayBuffer: buf });
      }
      throw new Error('mammoth unavailable');
    })
    .then(result => {
      content.innerHTML = result.value || '<p>El documento está vacío.</p>';
    })
    .catch(() => {
      const fname = decodeURIComponent(path.split('/').pop());
      content.innerHTML = `
        <div style="text-align:center;padding:60px 40px;color:#64748B;">
          <span class="material-symbols-outlined" style="font-size:56px;color:#00E5FF;opacity:0.6">description</span>
          <h3 style="color:#DDE2F5;margin:16px 0 8px">${fname.replace(/_/g,' ')}</h3>
          <p style="margin-bottom:24px">No se pudo previsualizar el documento en el navegador.<br>
          Descárgalo para abrirlo en tu aplicación de Office.</p>
          <a href="${path}" download
             style="display:inline-flex;align-items:center;gap:8px;
                    background:rgba(0,229,255,0.12);border:1px solid rgba(0,229,255,0.4);
                    border-radius:10px;padding:12px 24px;color:#00E5FF;font-weight:600;
                    text-decoration:none;font-size:14px;">
            <span class="material-symbols-outlined">download</span>Descargar Documento
          </a>
        </div>`;
    });
}

// Image Viewer
function loadImgViewer(paths) {
  _viewerState.images    = paths;
  _viewerState.currentImg= 0;
  const stage  = document.getElementById('imgViewerStage');
  const thumbs = document.getElementById('imgViewerThumbs');
  stage.innerHTML  = `<img id="imgViewerMain" src="${encodePath(paths[0])}" alt="Imagen 1" />`;
  thumbs.innerHTML = paths.map((p, i) =>
    `<img class="img-thumb${i===0?' active':''}" src="${encodePath(p)}" alt="Miniatura ${i+1}"
          onclick="showImgAt(${i})" loading="lazy" />`
  ).join('');
  document.getElementById('imgCounter').textContent = `1 / ${paths.length}`;
  document.getElementById('imgPrev').disabled = true;
  document.getElementById('imgNext').disabled = paths.length <= 1;
}

function showImgAt(idx) {
  const paths = _viewerState.images;
  if (idx < 0 || idx >= paths.length) return;
  _viewerState.currentImg = idx;
  const main = document.getElementById('imgViewerMain');
  if (main) main.src = encodePath(paths[idx]);
  document.getElementById('imgCounter').textContent = `${idx+1} / ${paths.length}`;
  document.querySelectorAll('.img-thumb').forEach((el,i) => el.classList.toggle('active', i===idx));
  document.getElementById('imgPrev').disabled = idx === 0;
  document.getElementById('imgNext').disabled = idx === paths.length - 1;
}

function navigateImg(dir) { showImgAt(_viewerState.currentImg + dir); }


// ===========================
// RESET PROGRESS
// ===========================
function showResetConfirm() {
  const btn = document.getElementById('dbResetBtn');
  if (btn) btn.style.display = 'none';
  const section = document.getElementById('dbResetSection');
  if (!section || document.getElementById('resetConfirmRow')) return;
  const row = document.createElement('div');
  row.className = 'reset-confirm-row';
  row.id = 'resetConfirmRow';
  row.innerHTML = `
    <span class="reset-confirm-text">\u00bfSeguro que deseas borrar todo tu progreso?</span>
    <button class="reset-confirm-yes" onclick="confirmResetProgress()">S\u00ed, reiniciar</button>
    <button class="reset-confirm-no"  onclick="cancelResetProgress()">Cancelar</button>`;
  section.appendChild(row);
}

function cancelResetProgress() {
  const row = document.getElementById('resetConfirmRow');
  if (row) row.remove();
  const btn = document.getElementById('dbResetBtn');
  if (btn) btn.style.display = '';
}

function confirmResetProgress() {
  try {
    const keys = Object.keys(localStorage);
    keys.forEach(k => { if (k.startsWith('enarmagic')) localStorage.removeItem(k); });
  } catch(e) {}
  cancelResetProgress();
  if (typeof window.renderDashboard === 'function') window.renderDashboard();
  const toast = document.createElement('div');
  toast.textContent = '\u2713 Progreso reiniciado correctamente';
  toast.style.cssText = `position:fixed;bottom:28px;left:50%;transform:translateX(-50%);
    background:#0D1528;border:1px solid rgba(6,214,160,0.4);border-radius:10px;
    padding:12px 28px;color:#06D6A0;font-size:13px;font-weight:600;z-index:9999;
    box-shadow:0 8px 32px rgba(0,0,0,0.6);pointer-events:none;`;
  document.body.appendChild(toast);
  setTimeout(() => toast.remove(), 3000);
}
